import React from 'react';
import { Outlet } from 'react-router-dom';

// I'm assuming these components exist based on a standard admin layout.
// If your component names or paths are different, please adjust the imports.
import Footer from './Footer';
import Navbar from './Navbar';
import Sidebar from './Sidebar';

const MasterLayout = () => {
    const handleSidebarToggle = (e) => {
        e.preventDefault();
        // This is the standard way the SB Admin template toggles the sidebar.
        // It adds/removes a class on the body element, which the CSS uses to show/hide the menu.
        document.body.classList.toggle('sb-sidenav-toggled');
    };

    return (
        <div className="sb-nav-fixed">
            <Navbar onToggleSidebar={handleSidebarToggle} />
            <div id="layoutSidenav">
                <div id="layoutSidenav_nav">
                    <Sidebar />
                </div>
                <div id="layoutSidenav_content">
                    <main>
                        {/* This Outlet is the crucial part. It acts as a placeholder and
                            renders the component of the matched child route (e.g., Dashboard, Category). */}
                        <Outlet />
                    </main>
                    <Footer />
                </div>
            </div>
        </div>
    );
};

export default MasterLayout;
